// TikTok postagem automática (pendente/assistida)
// Requer vídeo vertical e credenciais TikTok aprovadas
return [{ json: { status: "pendente_credencial", mensagem: "Pendente até haver vídeo vertical e credencial aprovada." } }];

// LinkedIn postagem na página/organização (pendente)
// LinkedIn requer texto institucional corporativo e credencial configurada
return [{ json: { status: "pendente_credencial", mensagem: "LinkedIn pendente até credencial de página/organização estar configurada." } }];

const instagramResult = $node["Instagram Publish (Meta API)"] ? $node["Instagram Publish (Meta API)"].json : null;
const facebookResult = $node["Facebook Page Feed (Meta API)"] ? $node["Facebook Page Feed (Meta API)"].json : null;
const gmbResult = $node["Google Business localPosts"].json;
const tiktokResult = $node["TikTok Publishing Node"].json;
const linkedinResult = $node["LinkedIn Publishing Node"].json;

const row = $node["Buscar Post Pronto Supabase"].json;

// Determinar status de cada canal
const statusInstagram = instagramResult && !instagramResult.error ? 'publicado' : 'falha';
const statusFacebook = facebookResult && !facebookResult.error ? 'publicado' : 'falha';
const statusGmb = 'pendente_credencial';
const statusTiktok = 'pendente_credencial';
const statusLinkedin = 'pendente_credencial';

const urlInstagram = instagramResult && instagramResult.id ? `https://instagram.com/p/${instagramResult.id}` : '';
const urlFacebook = facebookResult && facebookResult.id ? `https://facebook.com/${facebookResult.id}` : '';

const errosObj = {};
if (instagramResult && instagramResult.error) errosObj.instagram = instagramResult.error;
if (facebookResult && facebookResult.error) errosObj.facebook = facebookResult.error;

const tentativasObj = row.tentativas || {};
tentativasObj.instagram = (tentativasObj.instagram || 0) + 1;
tentativasObj.facebook = (tentativasObj.facebook || 0) + 1;

const publicadoEmObj = row.publicado_em || {};
const nowIso = new Date().toISOString();
if (statusInstagram === 'publicado') publicadoEmObj.instagram = nowIso;
if (statusFacebook === 'publicado') publicadoEmObj.facebook = nowIso;

// Calcular status global
let activeSuccess = 0;
let activeFail = 0;

if (statusInstagram === 'publicado') activeSuccess++;
else activeFail++;

if (statusFacebook === 'publicado') activeSuccess++;
else activeFail++;

let globalStatus = 'falhou_total';
if (activeSuccess === 2) {
  globalStatus = 'publicado_total';
} else if (activeSuccess > 0) {
  globalStatus = 'publicado_parcial';
} else if (activeFail === 0) {
  globalStatus = 'pendente_credencial';
} else {
  globalStatus = 'falhou_total';
}

return [{
  json: {
    id: row.id,
    status_instagram: statusInstagram,
    status_facebook: statusFacebook,
    status_google_business: statusGmb,
    status_tiktok: statusTiktok,
    status_linkedin: statusLinkedin,
    url_instagram: urlInstagram,
    url_facebook: urlFacebook,
    url_google_business: '',
    url_tiktok: '',
    url_linkedin: '',
    erros: errosObj,
    tentativas: tentativasObj,
    publicado_em: publicadoEmObj,
    status_global: globalStatus
  }
}];

